#include <stdio.h>
#include <stdint.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, K, X, Y;
        scanf("%lld %lld %lld %lld", &N, &K, &X, &Y);
        long long ans;
        if (X <= Y) ans = N * X;
        else ans = K * X + (N - K) * Y;
        printf("%lld\n", ans);
    }
    return 0;
}

