import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it)); X = int(next(it)); Y = int(next(it))
        if X <= Y:
            ans = N * X
        else:
            ans = K * X + (N - K) * Y
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

